export const JS_QUESTIONS: Question[] = JS_LOGIC_DATA.map((item, i) => {
  const index = i + 1;
  return {
    id: `j${index}`,
    topic: 'javascript',
    difficulty: getDifficulty(index),
    question: item.q,
    answer: item.a,
    code: item.c,
  };
});


